import { useState } from 'react';
import { Briefcase, BookOpen } from 'lucide-react';
import SectionHeader from './SectionHeader';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';

const logos = {
  'Commercial International Bank (CIB)': 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/2e/CIB_logo.svg/200px-CIB_logo.svg.png',
  'Banque Misr × Google': 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/2f/Google_2015_logo.svg/200px-Google_2015_logo.svg.png',
};

const fallbacks = {
  internship: { 'CIB':'🏦', 'ASORC':'🏭', 'Nile':'⛽' },
  training: { 'CIB':'📚', 'Google':'🌐', 'HSBC':'💼' },
};

function getFallback(e) {
  if (e.org.includes('CIB') && e.type === 'internship') return '🏦';
  if (e.org.includes('ASORC') || e.org.includes('Refining') || e.org.includes('البترول') && e.type==='internship') return '🏭';
  if (e.org.includes('Nile') || e.org.includes('النيل')) return '⛽';
  if (e.org.includes('CIB') && e.type === 'training') return '📚';
  if (e.org.includes('Google') || e.org.includes('Misr') || e.org.includes('مصر')) return '🌐';
  if (e.org.includes('HSBC')) return '💼';
  return e.type === 'internship' ? '🏢' : '📖';
}

export default function Experience() {
  const { dark, lang } = useApp();
  const tr = t[lang];
  const [filter, setFilter] = useState('all');
  const filtered = filter === 'all' ? tr.experiences : tr.experiences.filter(e => e.type === filter);

  const bg = dark ? 'bg-[#0f0f14]' : 'bg-cream';
  const cardBg = dark ? 'bg-[#13131e]' : 'bg-parchment';
  const textBase = dark ? 'text-white' : 'text-ink2';
  const textMuted = dark ? 'text-white/50' : 'text-muted';
  const textMuted2 = dark ? 'text-white/60' : 'text-muted2';
  const logoBg = dark ? 'bg-[#1a1a28]' : 'bg-cream';
  const filterInactive = dark ? 'bg-[#1a1a28] text-white/60 border-white/10 hover:text-white' : 'bg-parchment text-muted2 border-ink/10 hover:text-ink';
  const filterActive = dark ? 'bg-white text-[#0f0f14]' : 'bg-ink text-parchment';

  return (
    <section id="experience" className={`py-24 px-[5%] ${bg} transition-colors duration-300`}>
      <SectionHeader tag={tr.expTag} title={tr.expTitle} dark={dark} />

      <div className="flex gap-2 mb-10">
        {[[`all`,tr.all],[`internship`,tr.internships],[`training`,tr.training]].map(([val,label]) => (
          <button key={val} onClick={() => setFilter(val)}
            className={`px-4 py-1.5 rounded-full text-sm font-medium transition-all border ${filter===val ? filterActive : filterInactive}`}>
            {label}
          </button>
        ))}
      </div>

      <div className="grid md:grid-cols-2 gap-4">
        {filtered.map((e, i) => {
          const logoUrl = logos[e.org];
          const emoji = getFallback(e);
          return (
            <div key={`${filter}-${i}`}
              className={`${cardBg} rounded-2xl p-6 border-[1.5px] border-transparent shadow-sm transition-all duration-300 hover:-translate-y-1 hover:shadow-md ${
                e.type==='internship' ? 'hover:border-amber/20' : 'hover:border-teal/20'
              }`}
              style={{ animation: `fadeUp .4s ${i*0.07}s ease both` }}>
              <div className="flex items-start gap-4">
                <div className={`w-12 h-12 rounded-xl ${logoBg} flex items-center justify-center flex-shrink-0 overflow-hidden border border-ink/[.06]`}>
                  {logoUrl ? (
                    <>
                      <img src={logoUrl} alt={e.org} className="w-8 h-8 object-contain"
                        onError={ev => { ev.target.style.display='none'; ev.target.nextSibling.style.display='flex'; }} />
                      <span className="hidden text-xl items-center justify-center">{emoji}</span>
                    </>
                  ) : (
                    <span className="text-xl">{emoji}</span>
                  )}
                </div>
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 mb-1 flex-wrap">
                    <span className={`inline-flex items-center gap-1 text-[.6rem] font-semibold tracking-wider uppercase px-2 py-0.5 rounded-full ${
                      e.type==='internship' ? 'bg-amber/10 text-amber2' : 'bg-teal/10 text-teal2'
                    }`}>
                      {e.type==='internship' ? <Briefcase size={9}/> : <BookOpen size={9}/>}
                      {e.type==='internship' ? tr.internship : tr.training}
                    </span>
                    <span className={`text-[.65rem] ${textMuted}`}>{e.date}</span>
                  </div>
                  <h3 className={`font-semibold text-[.95rem] ${textBase} leading-tight`}>{e.role}</h3>
                  <p className={`text-[.78rem] ${textMuted} mt-0.5 mb-2`}>{e.org} · {e.location}</p>
                  <p className={`text-[.84rem] ${textMuted2} leading-[1.7]`}>{e.desc}</p>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </section>
  );
}
